SELECT generico5.categoria AS categoria FROM generico5 WHERE ((generico5.anunciante IN ('BANTRAB/TODOTICKET', 'TODOTICKET', 'TODOTICKET.COM')) AND (CAST(EXTRACT(YEAR FROM generico5.fecha) AS BIGINT) >= 2010) AND (CAST(EXTRACT(YEAR FROM generico5.fecha) AS BIGINT) <= 2015) AND (CAST(EXTRACT(YEAR FROM generico5.fecha) AS BIGINT) IN (2014, 2015)) AND (generico5.medio = 'PRENSA') AND (generico5.vehiculo IN ('Al Dia', 'El Periodico', 'Nuestro Diario', 'Prensa Libre', 'Siglo Veintiuno'))) GROUP BY generico5.categoria;
